// Entrada da tool, vinda do agente (LangGraph):
//   { "data": "2026-07-28",         // dia desejado (obrigatório)
//     "duracaoMin": 30,              // duração do atendimento (default 30)
//     "idCategoria": 1 }             // 1=avaliação (default). null = agenda toda
//
// Só monta o corpo da consulta ao Spine. A API é UTC e o endDate é EXCLUSIVO,
// então pede-se o dia seguinte e recorta-se depois pelo dia local.

const body = $json.body ?? $json;
const data = body.data;
if (!data || !/^\d{4}-\d{2}-\d{2}$/.test(data)) {
  throw new Error('Campo "data" (YYYY-MM-DD) é obrigatório.');
}

const d = new Date(data + 'T00:00:00Z');
const prox = new Date(d.getTime() + 86400000);
const iso = (x) => x.toISOString().slice(0, 10);

return [{
  json: {
    data,
    duracaoMin: Number(body.duracaoMin) || 30,
    idCategoria: body.idCategoria ?? 1,
    initialDate: data,
    endDate: iso(prox),
  },
}];

// ─── REGRA DE NEGÓCIO DA UNIDADE — CONFIRA COM A CLÍNICA ──────────────────
// Estes três blocos NÃO vêm da API do Doutor Hérnia (ela só devolve horário
// OCUPADO). São regra da unidade e ficam aqui, editáveis sem redeploy.
//
// Valores atuais medidos na agenda da Imperatriz: atendimentos entre 07h e 19h,
// em passos de 30 min. Almoço e sábado são SUPOSIÇÃO — ajuste.
const EXPEDIENTE = {
  // 0=dom 1=seg ... 6=sáb. Horas em formato "HH:MM". Dia ausente = fechado.
  1: [['07:00', '19:00']],
  2: [['07:00', '19:00']],
  3: [['07:00', '19:00']],
  4: [['07:00', '19:00']],
  5: [['07:00', '19:00']],
  6: [['07:00', '12:00']], // sábado — CONFIRMAR se atende
};
const BLOQUEIOS = [
  ['11:00', '12:00'], // almoço — CONFIRMAR horário
];
const PASSO_MIN = 30;
// ─────────────────────────────────────────────────────────────────────────

// Só estes três status realmente OCUPAM o horário. Desmarcado (57) e
// remarcado (41) DEVOLVEM o slot — tratá-los como ocupados esconderia horário
// livre da Sofia. Atendido (42) é passado, mas continua bloqueando aquele
// minuto para efeito de agenda.
const OCUPA = new Set([37, 38, 42]);

const pedido = $('Lê o pedido').first().json;
const data = pedido.data;
const duracaoMin = pedido.duracaoMin;

const OFFSET_H = -3; // Imperatriz, UTC-3, sem horário de verão
const toMin = (hhmm) => {
  const [h, m] = hhmm.split(':').map(Number);
  return h * 60 + m;
};
const fromMin = (min) =>
  `${String(Math.floor(min / 60)).padStart(2, '0')}:${String(min % 60).padStart(2, '0')}`;

// Dia da semana da data pedida (meio-dia UTC evita virar o dia por fuso).
const dow = new Date(data + 'T12:00:00Z').getUTCDay();
const janelas = EXPEDIENTE[dow] || [];
if (janelas.length === 0) {
  return [{ json: { data, duracaoMin, fechado: true, livres: [], ocupados: [] } }];
}

// Minutos ocupados pela agenda real (converte UTC → local e recorta pelo dia).
const ocupados = [];
for (const it of items) {
  const r = it.json;
  if (!r.dateAttendance || !OCUPA.has(r.idStatus)) continue;
  const utc = new Date(r.dateAttendance);
  const local = new Date(utc.getTime() + OFFSET_H * 3600000);
  if (local.toISOString().slice(0, 10) !== data) continue;
  const ini = local.getUTCHours() * 60 + local.getUTCMinutes();
  ocupados.push({ ini, fim: ini + duracaoMin, hora: fromMin(ini), paciente: (r.clientName || '').trim() });
}
ocupados.sort((a, b) => a.ini - b.ini);

// Um candidato colide se sobrepõe agenda ocupada ou um bloqueio fixo.
const blocos = BLOQUEIOS.map(([a, b]) => ({ ini: toMin(a), fim: toMin(b) }));
const colide = (ini, fim) =>
  ocupados.some((o) => ini < o.fim && fim > o.ini) ||
  blocos.some((b) => ini < b.fim && fim > b.ini);

// Varre o expediente em passos de PASSO_MIN e coleta os que cabem.
const livres = [];
for (const [aberto, fechado] of janelas) {
  const fimJan = toMin(fechado);
  for (let t = toMin(aberto); t + duracaoMin <= fimJan; t += PASSO_MIN) {
    if (!colide(t, t + duracaoMin)) livres.push(fromMin(t));
  }
}

return [{
  json: {
    data,
    duracaoMin,
    fechado: false,
    livres,
    ocupados: ocupados.map((o) => o.hora),
    resumo: livres.length
      ? `${livres.length} horários livres em ${data}: ${livres.join(', ')}`
      : `Sem horários livres em ${data}.`,
  },
}];
